import os
import socket
import subprocess
import time

import requests
from sglang.utils import print_highlight


def is_port_in_use(port: int) -> bool:
    """Check if a port is in use"""
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        try:
            s.bind(("localhost", port))
            return False
        except OSError:
            return True


def get_available_port():
    # get a random available port
    # and try to find a port that is not in use
    for port in range(10000, 65535):
        if not is_port_in_use(port):
            return port
    raise RuntimeError("No available port found")


def execute_shell_command(
    command: str,
    disable_proxy: bool = False,
    enable_hf_mirror: bool = False,
    sglang_use_modelscope: bool = False,
    start_new_session: bool = False,
):
    """Execute a shell command and return its process handle."""
    command = command.replace("\\\n", " ").replace("\\", " ")
    env = os.environ.copy()

    if disable_proxy:
        for name in (
            "http_proxy",
            "https_proxy",
            "no_proxy",
            "HTTP_PROXY",
            "HTTPS_PROXY",
            "NO_PROXY",
        ):
            env.pop(name, None)

    if enable_hf_mirror:
        env["HF_ENDPOINT"] = "https://hf-mirror.com"
    if sglang_use_modelscope:
        env["SGLANG_USE_MODELSCOPE"] = "true"
    return subprocess.Popen(
        command.split(),
        text=True,
        stderr=subprocess.STDOUT,
        env=env,
        start_new_session=start_new_session,
    )


def terminate_process_trees(*processes: subprocess.Popen, grace_s: float = 30) -> None:
    """Terminate subprocess sessions, including descendants of dead leaders."""
    active = tuple(process for process in processes if process is not None)
    if not active:
        return

    # SGLang's launcher exits independently from its scheduler/model workers.
    # Reuse the supervisor's process-group cleanup so a dead launcher cannot
    # leave GPU-owning descendants alive for the next test or workflow step.
    from specforge.launch_plan import _terminate_processes

    exited_group_leaders = tuple(
        process for process in active if process.poll() is not None
    )
    _terminate_processes(
        active,
        grace_s=grace_s,
        exited_group_leaders=exited_group_leaders,
    )


def wait_for_server(
    base_url: str,
    timeout: int | None = None,
    disable_proxy: bool = False,
    process: subprocess.Popen | None = None,
) -> None:
    """Wait until a server's OpenAI-compatible models endpoint is ready."""
    started = time.perf_counter()
    proxy_names = (
        "http_proxy",
        "https_proxy",
        "no_proxy",
        "HTTP_PROXY",
        "HTTPS_PROXY",
        "NO_PROXY",
    )
    saved_proxies = {}
    if disable_proxy:
        saved_proxies = {
            name: os.environ.pop(name) for name in proxy_names if name in os.environ
        }

    try:
        while True:
            if process is not None and process.poll() is not None:
                raise RuntimeError(
                    f"Server process exited with code {process.returncode}"
                )
            try:
                response = requests.get(
                    f"{base_url}/v1/models",
                    headers={"Authorization": "Bearer None"},
                    timeout=5,
                )
                if response.status_code == 200:
                    time.sleep(5)
                    print_highlight(
                        "Server is ready; server and test output may be interleaved."
                    )
                    return
            except requests.exceptions.RequestException:
                pass

            if timeout is not None and time.perf_counter() - started > timeout:
                raise TimeoutError("Server did not become ready within timeout period")
            time.sleep(1)
    finally:
        os.environ.update(saved_proxies)

from __future__ import annotations

import unittest
from dataclasses import FrozenInstanceError, fields, is_dataclass
from enum import Enum

from specforge.algorithms import (
    AlgorithmCapabilities,
    AlgorithmSpec,
    DraftRequirement,
    FeatureContract,
    FeatureMode,
    OfflineStorageContract,
)


def _offline(modality: str = "text") -> FeatureContract:
    return FeatureContract(
        mode=FeatureMode.OFFLINE,
        modality=modality,
        required_tensors={"input_ids", "hidden_states", "loss_mask"},
        allowed_target_representations={"hidden_state"},
        default_target_representation="hidden_state",
        storage=OfflineStorageContract(
            format="manifest_v1",
            required_tensors={"input_ids", "hidden_states", "loss_mask"},
            normalizer="eagle3_offline_v1",
        ),
    )


def _streaming(modality: str = "text") -> FeatureContract:
    required = {"input_ids", "hidden_state", "target", "loss_mask"}
    if modality == "vision_language":
        required.add("position_ids")
    return FeatureContract(
        mode=FeatureMode.STREAMING,
        modality=modality,
        required_tensors=required,
        allowed_target_representations={"hidden_state"},
        default_target_representation="hidden_state",
    )


def _spec(*contracts: FeatureContract) -> AlgorithmSpec:
    return AlgorithmSpec(
        name="eagle3",
        draft=DraftRequirement(
            compatible_architectures={"LlamaForCausalLMEagle3"},
            default_architecture="LlamaForCausalLMEagle3",
            supported_overrides={"attention_layout", "num_hidden_layers"},
        ),
        feature_contracts=contracts or (_offline(), _streaming()),
        capabilities=AlgorithmCapabilities(
            attention_backends={"sdpa", "flex_attention"},
            supports_compact_teacher=True,
            supports_vocab_mapping=True,
        ),
    )

