def _payload(
    algorithm: str = "eagle3",
    *,
    mode: str = "online",
    modality: str = "text",
) -> dict:
    model = {
        "target_model_path": "target",
        "draft_model_config": "draft.json",
        "input_modality": modality,
    }
    if algorithm in {"eagle3", "peagle"} and mode == "online":
        model["vocab_mapping_path"] = "mapping.pt"
    training = {
        "strategy": algorithm,
        "max_steps": 1,
        "attention_backend": "flex_attention",
        "batch_size": 1,
    }
    if mode == "offline":
        return {
            "model": model,
            "data": {"hidden_states_path": "features"},
            "training": training,
        }
    return {
        "model": model,
        "data": {"train_data_path": "prompts.jsonl"},
        "training": training,
        "deployment": {
            "mode": "disaggregated",
            "disaggregated": {
                "control_dir": "outputs/test/control",
                "backend": "mooncake",
                "server_urls": ["http://capture:30000"],
            },

#!/usr/bin/env bash
# Thin online-disaggregated example over the one public training entry.
set -euo pipefail

if [[ "${1:-}" == -h || "${1:-}" == --help ]]; then
    printf '%s\n' \
        "Usage: CONFIG=path/to/online-disagg.yaml $0 [SPECFORGE_TRAIN_ARG ...]" \
        "Example: CONFIG=... $0 --role producer" \
        "With no --role, a single-node config supervises producer and consumer."
    exit 0
fi

config=${CONFIG:-}
[[ -n "$config" ]] || {
    printf 'error: set CONFIG\n' >&2
    exit 2
}
[[ -f "$config" ]] || {
    printf 'error: CONFIG does not exist: %s\n' "$config" >&2
    exit 2
}

specforge_bin=$(command -v specforge) || {
    printf 'error: specforge is not on PATH\n' >&2
    exit 2
}
exec "$specforge_bin" train --config "$config" "$@"
